import { defineConfig, loadEnv } from 'vite';
import react from '@vitejs/plugin-react';

// vite config
// spent way too long debugging cookie issues here before lol

export default ({ mode }) => {

// loading env manually because I always forget
// vite only exposes vars starting with VITE_
const env = loadEnv(mode, '.', '');

return defineConfig({

plugins: [
  react()
],

server: {

  port: 3001,

  proxy: {

    '/api': {

      target: env.VITE_TARGET,

      secure: false, // local dev only probably
      changeOrigin: true,

      configure: (proxyServer) => {

        // intercepting proxy response to clean cookies a bit
        proxyServer.on('proxyRes', (proxyRes) => {

          const cookies = proxyRes.headers['set-cookie'];

          if (!cookies) {
            return;
          }

          // normalizing because sometimes it's a string
          const cookieList = Array.isArray(cookies)
            ? cookies
            : [cookies];

          proxyRes.headers['set-cookie'] = cookieList.map((cookie) => {

            let updatedCookie = cookie;

            // secure cookies were breaking localhost testing
            updatedCookie = updatedCookie.replace(/; *Secure/gi, '');

            // removing SameSite=None for local browser behavior
            updatedCookie = updatedCookie.replace(/; *SameSite=None/gi, '');

            // backend domain was conflicting locally
            updatedCookie = updatedCookie.replace(/; *Domain=[^;]+/gi, '');

            return updatedCookie;
          });

        });

        // maybe useful later
        // proxyServer.on('error', (err) => {
        //   console.log('proxy crashed:', err);
        // });

      },
    },

  },

},

});
};